const execAsync = promisify(exec);

// ── Hermetic Git ─────────────────────────────────────────────

beforeAll(() => { setupHermeticGit(); });
afterAll(() => { teardownHermeticGit(); });

// ── Helpers ──────────────────────────────────────────────────

let db: Database;

function makeId(): string {
  return `wt-${Date.now()}-${Math.random().toString(16).substring(2, 8)}`;
}

function makeWorkGroupId(): string {
  return `wg-${Date.now()}-${Math.random().toString(16).substring(2, 8)}`;
}

function insertReadyWorktree(wgId: string, specPath: string, branch: string): string {
  const id = makeId();
  insertWorktree(db, {
    id,
    work_group_id: wgId,
    spec_path: specPath,
    branch,
    worktree_path: `/tmp/wt-${id}`,
    status: 'created',
  });
  transitionWorktreeStatus(db, id, 'running');
  transitionWorktreeStatus(db, id, 'complete');
  transitionWorktreeStatus(db, id, 'ready');
  return id;
}

// ── Conflict detection via git ──────────────────────────────

describe('conflict resolution: git conflict detection', () => {
  let tmpDir: string;

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-conflict-test-'));
    await execAsync('git init', { cwd: tmpDir });
    await execAsync('git config user.email "test@test.com"', { cwd: tmpDir });
    await execAsync('git config user.name "Test"', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'shared.txt'), 'original');
    await execAsync('git add . && git commit -m "init"', { cwd: tmpDir });
  });

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true });
  });

  test('detects merge conflicts via exit code', async () => {
    // Create conflicting branches
    await execAsync('git checkout -b branch-a', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'shared.txt'), 'version A');
    await execAsync('git add . && git commit -m "A"', { cwd: tmpDir });

    await execAsync('git checkout main', { cwd: tmpDir });
    await execAsync('git checkout -b branch-b', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'shared.txt'), 'version B');
    await execAsync('git add . && git commit -m "B"', { cwd: tmpDir });

    // Start consolidation
    await execAsync('git checkout -b consolidation main', { cwd: tmpDir });
    await execAsync('git merge --no-ff branch-a -m "merge A"', { cwd: tmpDir });

    // Merge branch-b causes CONFLICT
    let hadConflict = false;
    try {
      await execAsync('git merge --no-ff branch-b -m "merge B"', { cwd: tmpDir });
    } catch (err: unknown) {
      const e = err as { stderr?: string; stdout?: string };
      const output = (e.stderr || '') + (e.stdout || '');
      hadConflict = output.includes('CONFLICT') || output.includes('Merge conflict');
    }
    expect(hadConflict).toBe(true);

    // Abort to clean up
    await execAsync('git merge --abort', { cwd: tmpDir });
  });

  test('lists conflicted files via git diff --diff-filter=U', async () => {
    // Create conflicting changes on same file
    await execAsync('git checkout -b feat-x', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'shared.txt'), 'feat X content');
    await execAsync('git add . && git commit -m "feat X"', { cwd: tmpDir });

    await execAsync('git checkout main', { cwd: tmpDir });
    await execAsync('git checkout -b feat-y', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'shared.txt'), 'feat Y content');
    await execAsync('git add . && git commit -m "feat Y"', { cwd: tmpDir });

    await execAsync('git checkout -b consolidation main', { cwd: tmpDir });
    await execAsync('git merge --no-ff feat-x -m "merge X"', { cwd: tmpDir });

    try {
      await execAsync('git merge --no-ff feat-y -m "merge Y"', { cwd: tmpDir });
    } catch {
      // Expected conflict
    }

    const { stdout } = await execAsync('git diff --name-only --diff-filter=U', { cwd: tmpDir });
    const conflicted = stdout.trim().split('\n').filter(f => f.length > 0);
    expect(conflicted).toContain('shared.txt');

    await execAsync('git merge --abort', { cwd: tmpDir });
  });

  test('git merge --abort reverts the failed merge', async () => {
    // Setup conflict
    await execAsync('git checkout -b a', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'shared.txt'), 'change A');
    await execAsync('git add . && git commit -m "A"', { cwd: tmpDir });

    await execAsync('git checkout main', { cwd: tmpDir });
    await execAsync('git checkout -b b', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'shared.txt'), 'change B');
    await execAsync('git add . && git commit -m "B"', { cwd: tmpDir });

    await execAsync('git checkout -b consolidation main', { cwd: tmpDir });
    await execAsync('git merge --no-ff a -m "merge a"', { cwd: tmpDir });

    const { stdout: preMerge } = await execAsync('git rev-parse HEAD', { cwd: tmpDir });

    try {
      await execAsync('git merge --no-ff b -m "merge b"', { cwd: tmpDir });
    } catch { /* conflict */ }

    await execAsync('git merge --abort', { cwd: tmpDir });

    const { stdout: postAbort } = await execAsync('git rev-parse HEAD', { cwd: tmpDir });
    expect(postAbort.trim()).toBe(preMerge.trim());

    // Working dir should be clean
    const { stdout: status } = await execAsync('git status --porcelain', { cwd: tmpDir });
    expect(status.trim()).toBe('');
  });

  test('multiple files can conflict simultaneously', async () => {
    // Create two files with conflicting content
    await fs.writeFile(path.join(tmpDir, 'file1.txt'), 'original 1');
    await fs.writeFile(path.join(tmpDir, 'file2.txt'), 'original 2');
    await execAsync('git add . && git commit -m "add files"', { cwd: tmpDir });

    await execAsync('git checkout -b alpha', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'file1.txt'), 'alpha 1');
    await fs.writeFile(path.join(tmpDir, 'file2.txt'), 'alpha 2');
    await execAsync('git add . && git commit -m "alpha changes"', { cwd: tmpDir });

    await execAsync('git checkout main', { cwd: tmpDir });
    await execAsync('git checkout -b beta', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'file1.txt'), 'beta 1');
    await fs.writeFile(path.join(tmpDir, 'file2.txt'), 'beta 2');
    await execAsync('git add . && git commit -m "beta changes"', { cwd: tmpDir });

    await execAsync('git checkout -b consolidation main', { cwd: tmpDir });
    await execAsync('git merge --no-ff alpha -m "merge alpha"', { cwd: tmpDir });

    try {
      await execAsync('git merge --no-ff beta -m "merge beta"', { cwd: tmpDir });
    } catch { /* conflict */ }

    const { stdout } = await execAsync('git diff --name-only --diff-filter=U', { cwd: tmpDir });
    const conflicted = stdout.trim().split('\n').filter(f => f.length > 0);
    expect(conflicted.length).toBe(2);
    expect(conflicted).toEqual(expect.arrayContaining(['file1.txt', 'file2.txt']));

    await execAsync('git merge --abort', { cwd: tmpDir });
  });
});

// ── Worktree status transitions for conflict resolution ─────

describe('conflict resolution: status transitions', () => {
  beforeEach(() => { db = getTestDb(); });

  test('merging -> paused stores conflicted file list in error column', () => {
    const wgId = makeWorkGroupId();
    const id = insertReadyWorktree(wgId, 'conflict.md', 'forge/conflict');

    transitionWorktreeStatus(db, id, 'merging');
    transitionWorktreeStatus(db, id, 'paused', 'Unresolved merge conflicts: src/auth.ts, src/api.ts');

    const wt = getWorktree(db, id)!;
    expect(wt.status).toBe('paused');
    expect(wt.error).toContain('src/auth.ts');
    expect(wt.error).toContain('src/api.ts');
  });

  test('paused -> merging allows resume after manual fix', () => {
    const wgId = makeWorkGroupId();
    const id = insertReadyWorktree(wgId, 'resume.md', 'forge/resume');

    transitionWorktreeStatus(db, id, 'merging');
    transitionWorktreeStatus(db, id, 'paused');
    transitionWorktreeStatus(db, id, 'merging');
    expect(getWorktree(db, id)!.status).toBe('merging');
  });

  test('merging -> paused is distinct from merging -> merge_failed', () => {
    const wgId = makeWorkGroupId();
    const pausedId = insertReadyWorktree(wgId, 'paused.md', 'forge/paused');
    const failedId = insertReadyWorktree(wgId, 'failed.md', 'forge/failed');

    transitionWorktreeStatus(db, pausedId, 'merging');
    transitionWorktreeStatus(db, pausedId, 'paused', 'Git conflict');

    transitionWorktreeStatus(db, failedId, 'merging');
    transitionWorktreeStatus(db, failedId, 'merge_failed', 'Type error');

    expect(getWorktree(db, pausedId)!.status).toBe('paused');
    expect(getWorktree(db, failedId)!.status).toBe('merge_failed');
  });
});

// ── Post-resolution type-check retries ──────────────────────

describe('conflict resolution: type-check retry logic', () => {
  test('up to 2 retry attempts with error feedback (logic verification)', () => {
    const maxRetries = 2;
    let attempts = 0;
    let fixed = false;

    // Simulate: type-check fails, agent attempts fixes
    for (let attempt = 1; attempt <= maxRetries; attempt++) {
      attempts++;
      // Simulate agent fix attempt that fails
      const agentFixed = attempt === maxRetries; // fixes on last try
      if (agentFixed) {
        fixed = true;
        break;
      }
    }

    expect(attempts).toBe(2);
    expect(fixed).toBe(true);
  });

  test('exceeding max retries transitions to paused', () => {
    db = getTestDb();
    const wgId = makeWorkGroupId();
    const id = insertReadyWorktree(wgId, 'retry-fail.md', 'forge/retry-fail');

    transitionWorktreeStatus(db, id, 'merging');

    // Simulate: all retry attempts failed
    transitionWorktreeStatus(db, id, 'paused', 'Type errors after conflict resolution: src/main.ts');
    expect(getWorktree(db, id)!.status).toBe('paused');
  });
});

// ── Transitive skip propagation ─────────────────────────────

describe('conflict resolution: transitive dependency skip', () => {
  beforeEach(() => { db = getTestDb(); });

  test('skips transitive dependents of paused worktree', () => {
    const specs: SpecDep[] = [
      { name: 'base.md', path: '/base.md', depends: [] },
      { name: 'child.md', path: '/child.md', depends: ['base.md'] },
      { name: 'grandchild.md', path: '/grandchild.md', depends: ['child.md'] },
    ];

    const failedSpecs = new Set<string>();
    const skipped: string[] = [];

    // base.md gets paused (conflict)
    failedSpecs.add('base.md');

    // child depends on paused base
    const childBlocked = specs[1].depends.find(d => failedSpecs.has(d));
    expect(childBlocked).toBe('base.md');
    skipped.push('child.md');
    failedSpecs.add('child.md');

    // grandchild depends on skipped child
    const gcBlocked = specs[2].depends.find(d => failedSpecs.has(d));
    expect(gcBlocked).toBe('child.md');
    skipped.push('grandchild.md');

    expect(skipped).toEqual(['child.md', 'grandchild.md']);
  });

  test('skipped dependents remain in ready status', () => {
    const wgId = makeWorkGroupId();
    const id = insertReadyWorktree(wgId, 'skipped.md', 'forge/skipped');

    // Never transitioned away from ready
    expect(getWorktree(db, id)!.status).toBe('ready');
  });

  test('consolidation continues with non-dependent worktrees', () => {
    const specs: SpecDep[] = [
      { name: 'base.md', path: '/base.md', depends: [] },
      { name: 'independent.md', path: '/ind.md', depends: [] },
      { name: 'child.md', path: '/child.md', depends: ['base.md'] },
    ];

    const failedSpecs = new Set<string>(['base.md']);

    // independent.md has no deps on base -- should proceed
    const indBlocked = specs[1].depends.find(d => failedSpecs.has(d));
    expect(indBlocked).toBeUndefined();

    // child.md blocked by base
    const childBlocked = specs[2].depends.find(d => failedSpecs.has(d));
    expect(childBlocked).toBe('base.md');
  });
});

// ── Git reset for rollback ──────────────────────────────────

describe('conflict resolution: git reset --hard HEAD~1 rollback', () => {
  let tmpDir: string;

  beforeEach(async () => {
    tmpDir = await fs.mkdtemp(path.join(os.tmpdir(), 'forge-rollback-test-'));
    await execAsync('git init', { cwd: tmpDir });
    await execAsync('git config user.email "test@test.com"', { cwd: tmpDir });
    await execAsync('git config user.name "Test"', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'base.txt'), 'base');
    await execAsync('git add . && git commit -m "init"', { cwd: tmpDir });
  });

  afterEach(async () => {
    await fs.rm(tmpDir, { recursive: true, force: true });
  });

  test('git reset --hard HEAD~1 reverts last merge commit', async () => {
    // Create and merge a feature
    await execAsync('git checkout -b feature', { cwd: tmpDir });
    await fs.writeFile(path.join(tmpDir, 'feat.txt'), 'feature');
    await execAsync('git add . && git commit -m "feature"', { cwd: tmpDir });

    await execAsync('git checkout main', { cwd: tmpDir });
    await execAsync('git merge --no-ff feature -m "merge feature"', { cwd: tmpDir });

    const { stdout: preSha } = await execAsync('git rev-parse HEAD~1', { cwd: tmpDir });

    // Roll back the merge
    await execAsync('git reset --hard HEAD~1', { cwd: tmpDir });

    const { stdout: postSha } = await execAsync('git rev-parse HEAD', { cwd: tmpDir });
    expect(postSha.trim()).toBe(preSha.trim());

    // Feature file should be gone
    const exists = await fs.access(path.join(tmpDir, 'feat.txt')).then(() => true).catch(() => false);
    expect(exists).toBe(false);
  });
});

// ── Consolidation summary report ────────────────────────────

describe('conflict resolution: summary report', () => {
  test('summary includes merged, paused, and skipped counts', () => {
    const merged = ['wt-1', 'wt-2', 'wt-3'];
    const paused = ['wt-4'];
    const skipped = ['wt-5', 'wt-6'];

    const parts = [`${merged.length} merged`];
    if (paused.length > 0) parts.push(`${paused.length} paused`);
    if (skipped.length > 0) parts.push(`${skipped.length} skipped`);

    const summary = parts.join(', ');
    expect(summary).toBe('3 merged, 1 paused, 2 skipped');
  });
});
